import React, { useState, useEffect } from 'react';
import { 
  Briefcase, 
  Target, 
  TrendingUp, 
  AlertTriangle, 
  Users, 
  BrainCircuit, 
  ArrowRight,
  DollarSign,
  Activity,
  Layers,
  Sparkles,
  Zap,
  ShieldAlert,
  Wallet,
  Smartphone,
  BarChart2,
  Search,
  Crosshair,
  Share2,
  Flag,
  FileText,
  Calendar,
  CheckCircle2,
  AlertCircle
} from 'lucide-react';
import { ClientProfile, ClientStage, InsightResponse } from '../types';
import { TrendChart, CompetitorChart, FunnelChart, DonutChart, MultiLineChart } from './Charts';
import { generateClientInsight } from '../services/geminiService';

interface ClientDetailProps {
  client: ClientProfile;
}

export const ClientDetail: React.FC<ClientDetailProps> = ({ client }) => {
  const [insight, setInsight] = useState<InsightResponse | null>(null);
  const [loadingInsight, setLoadingInsight] = useState(false);
  const [activeTab, setActiveTab] = useState('performance');

  // Reset insight and tab when client changes
  useEffect(() => {
    setInsight(null);
    // Set default tab based on stage
    if (client.stage === ClientStage.PROSPECT) {
      setActiveTab('prospect');
    } else if (client.stage === ClientStage.CHURN) {
      setActiveTab('churn');
    } else {
      setActiveTab('performance');
    }
  }, [client.id]);

  const handleGenerateInsight = async () => {
    setLoadingInsight(true);
    try {
      const data = await generateClientInsight(client);
      setInsight(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingInsight(false);
    }
  };

  const renderHeader = () => (
    <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
      <div className="flex items-center gap-4">
        <img src={client.logo} alt={client.name} className="w-16 h-16 rounded-lg object-cover bg-gray-50" />
        <div>
          <h1 className="text-2xl font-bold text-gray-900">{client.name}</h1>
          <div className="flex items-center gap-2 text-sm text-gray-500 mt-1">
            <span className="flex items-center gap-1"><Briefcase size={14} /> {client.industry}</span>
            <span>•</span>
            <span className="flex items-center gap-1"><Layers size={14} /> {client.apps.length} 个应用</span>
          </div>
        </div>
      </div>
      <div className="flex items-center gap-3">
        <span className={`px-4 py-2 rounded-full text-sm font-semibold 
          ${client.stage === ClientStage.ACTIVE ? 'bg-green-100 text-green-700' : 
            client.stage === ClientStage.PROSPECT ? 'bg-blue-100 text-blue-700' : 
            'bg-red-100 text-red-700'}`}>
          {client.stage === ClientStage.PROSPECT && '拓展期 / 潜在客户'}
          {client.stage === ClientStage.ACTIVE && '活跃期 / 投放中'}
          {client.stage === ClientStage.CHURN && '流失期 / 风险客户'}
        </span>
      </div>
    </div>
  );

  const renderEmptyState = (message: string) => (
    <div className="flex flex-col items-center justify-center py-16 bg-white rounded-xl border border-dashed border-gray-300">
      <div className="bg-gray-50 p-4 rounded-full mb-3">
        <FileText className="text-gray-400" size={32} />
      </div>
      <h3 className="text-gray-900 font-medium mb-1">暂无数据</h3>
      <p className="text-gray-500 text-sm">{message}</p>
    </div>
  );

  const renderProspectTab = () => {
    // If we have minimal prospect data or if it's an active client with prospect history
    const steps = ['Lead', 'Contacted', 'Meeting', 'Negotiation', 'Onboarding'];
    const stepLabels = ['线索', '已联系', '会议', '谈判', '入驻'];
    const currentStepIdx = steps.indexOf(client.prospectStage || (client.stage === ClientStage.ACTIVE ? 'Onboarding' : 'Lead'));

    return (
      <div className="space-y-6">
        {/* Pipeline Progress */}
        <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
          <h3 className="text-lg font-semibold text-gray-800 mb-6 flex items-center gap-2">
            <Flag size={18} className="text-blue-600"/> 拓展漏斗与进度
          </h3>
          <div className="relative flex items-center justify-between w-full px-4">
            <div className="absolute left-0 top-1/2 transform -translate-y-1/2 w-full h-1 bg-gray-100 -z-10" />
            {stepLabels.map((step, idx) => (
              <div key={step} className="flex flex-col items-center bg-white px-2">
                <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold mb-2 transition-colors border-2
                  ${idx <= currentStepIdx ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white border-gray-300 text-gray-400'}`}>
                  {idx + 1}
                </div>
                <span className={`text-xs ${idx === currentStepIdx ? 'font-bold text-blue-600' : 'text-gray-500'}`}>
                  {step}
                </span>
              </div>
            ))}
          </div>

          <div className="mt-8 grid grid-cols-1 md:grid-cols-3 gap-4">
             <div className="p-4 bg-gray-50 rounded-lg border border-gray-100">
                <div className="text-xs text-gray-500 mb-1">最后联系时间</div>
                <div className="font-medium text-gray-900">{client.lastContactDate || '暂无记录'}</div>
             </div>
             <div className="p-4 bg-gray-50 rounded-lg border border-gray-100">
                <div className="text-xs text-gray-500 mb-1">负责 BD</div>
                <div className="font-medium text-gray-900">{client.bdOwner || '未分配'}</div>
             </div>
             <div className="p-4 bg-blue-50 rounded-lg border border-blue-100">
                <div className="text-xs text-blue-800 mb-1">下一步建议</div>
                <div className="font-medium text-blue-900 text-sm">
                    {client.stage === ClientStage.ACTIVE ? '定期回访，挖掘增量预算' : '安排商务会议讨论具体条款'}
                </div>
             </div>
          </div>
        </div>

        {/* Competitor Intel */}
        <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
             <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center gap-2">
                <Search size={18} className="text-blue-600"/> 竞品情报
             </h3>
             <div className="flex flex-col md:flex-row gap-6 items-center">
                 <div className="flex-1">
                    <p className="text-gray-600 mb-4 text-sm leading-relaxed">
                    该客户主要在 <strong>{client.competitorPlatforms[0] || '未知平台'}</strong> 投入预算。
                    根据市场情报，其在该平台的平均 CPI 约为 $2.50，日均消耗约 $5,000。
                    我方可以通过提供更优的 ROI 或 $2.10 的试投方案来争取预算份额。
                    </p>
                    <button className="text-blue-600 font-medium text-sm flex items-center gap-1 hover:underline">
                    查看详细竞品分析报告 <ArrowRight size={14} />
                    </button>
                 </div>
                 <div className="w-full md:w-1/3 p-4 bg-gray-50 rounded-lg">
                    <div className="text-xs text-gray-500 mb-2">主要竞品平台</div>
                    <div className="flex flex-wrap gap-2">
                        {client.competitorPlatforms.map(p => (
                            <span key={p} className="px-2 py-1 bg-white border border-gray-200 rounded text-xs text-gray-700">{p}</span>
                        ))}
                    </div>
                 </div>
             </div>
        </div>
      </div>
    );
  };

  const renderPerformanceTab = () => {
    if (!client.spendTrend && !client.conversionMetrics) {
        return renderEmptyState("该客户尚未产生足够的分发数据");
    }

    // 假设当前时间进度为 Q1 结束 (Mock 数据截止到 3 月)
    const mockCurrentTimeProgress = 25.0; 
    const budgetProgress = client.annualBudget ? Math.min((client.budgetSpent || 0) / client.annualBudget * 100, 100) : 0;
    const paceDiff = budgetProgress - mockCurrentTimeProgress;

    let paceStatus: 'normal' | 'under' | 'over' = 'normal';
    if (paceDiff < -5) paceStatus = 'under';
    if (paceDiff > 5) paceStatus = 'over';

    return (
        <div className="space-y-6">
            {/* Goal Analysis & Risk Forecast (New Section) */}
            <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
                <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-4">
                    <Target size={18} className="text-indigo-600"/> 目标分析与风险预报
                </h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    {/* Progress Bars */}
                    <div className="space-y-6">
                         <div>
                            <div className="flex justify-between text-sm mb-1">
                                <span className="text-gray-600 flex items-center gap-1"><Calendar size={14}/> 时间进度 (Q1 End)</span>
                                <span className="font-medium text-gray-900">{mockCurrentTimeProgress}%</span>
                            </div>
                            <div className="w-full bg-gray-100 rounded-full h-2.5">
                                <div className="bg-gray-400 h-2.5 rounded-full" style={{width: `${mockCurrentTimeProgress}%`}}></div>
                            </div>
                         </div>
                         <div>
                            <div className="flex justify-between text-sm mb-1">
                                <span className="text-gray-600 flex items-center gap-1"><Wallet size={14}/> 预算消耗进度</span>
                                <span className={`font-medium ${paceStatus === 'over' ? 'text-red-600' : paceStatus === 'under' ? 'text-amber-600' : 'text-green-600'}`}>
                                    {budgetProgress.toFixed(1)}% (${(client.budgetSpent || 0).toLocaleString()})
                                </span>
                            </div>
                            <div className="w-full bg-gray-100 rounded-full h-2.5 relative">
                                <div 
                                    className={`h-2.5 rounded-full ${paceStatus === 'over' ? 'bg-red-500' : paceStatus === 'under' ? 'bg-amber-500' : 'bg-green-500'}`} 
                                    style={{width: `${budgetProgress}%`}}
                                ></div>
                                {/* Benchmark Marker */}
                                <div 
                                    className="absolute top-[-4px] w-0.5 h-5 bg-black/20 z-10" 
                                    style={{left: `${mockCurrentTimeProgress}%`}}
                                    title="Time Benchmark"
                                ></div>
                            </div>
                         </div>
                    </div>

                    {/* Analysis Text Box */}
                    <div className={`rounded-lg p-4 border flex items-start gap-3 ${
                        paceStatus === 'normal' ? 'bg-green-50 border-green-100' : 
                        paceStatus === 'under' ? 'bg-amber-50 border-amber-100' : 
                        'bg-red-50 border-red-100'
                    }`}>
                        <div className="mt-0.5 flex-shrink-0">
                            {paceStatus === 'normal' && <CheckCircle2 className="text-green-600" size={20}/>}
                            {paceStatus === 'under' && <AlertTriangle className="text-amber-600" size={20}/>}
                            {paceStatus === 'over' && <AlertCircle className="text-red-600" size={20}/>}
                        </div>
                        <div>
                            <h4 className={`text-sm font-bold mb-1 ${
                                paceStatus === 'normal' ? 'text-green-800' : 
                                paceStatus === 'under' ? 'text-amber-800' : 
                                'text-red-800'
                            }`}>
                                {paceStatus === 'normal' && "进度健康：预算与时间匹配"}
                                {paceStatus === 'under' && "风险预警：预算消耗滞后 (Under-pacing)"}
                                {paceStatus === 'over' && "风险预警：预算消耗过快 (Over-pacing)"}
                            </h4>
                            <p className={`text-xs leading-relaxed ${
                                paceStatus === 'normal' ? 'text-green-700' : 
                                paceStatus === 'under' ? 'text-amber-700' : 
                                'text-red-700'
                            }`}>
                                {paceStatus === 'normal' && "当前消耗节奏符合年度规划，建议继续保持当前竞价策略，并监控即将到来的节假日流量波动。"}
                                {paceStatus === 'under' && `当前预算消耗落后于时间进度 ${(Math.abs(paceDiff)).toFixed(1)}%。可能原因为出价竞争力不足或定向圈层过窄。建议：1. 提高核心人群出价 10-15%；2. 拓展 Lookalike 相似人群包。`}
                                {paceStatus === 'over' && `当前预算消耗超前 ${(paceDiff).toFixed(1)}%。虽然量级充足，但可能面临下半年预算不足风险。建议：1. 降低长尾渠道出价；2. 审查低 ROI 素材，进行优胜劣汰。`}
                            </p>
                        </div>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
                <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
                    <div className="text-gray-500 text-xs mb-1">总消耗 (Total Spend)</div>
                    <div className="text-xl font-bold text-gray-900">${(client.totalSpend || 0).toLocaleString()}</div>
                    <div className="text-green-600 text-xs mt-1 flex items-center"><TrendingUp size={10} className="mr-1"/> +12%</div>
                </div>
                <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
                    <div className="text-gray-500 text-xs mb-1">综合 ROI</div>
                    <div className="text-xl font-bold text-gray-900">{client.roi}x</div>
                    <div className="text-gray-400 text-xs mt-1">目标: 2.0x</div>
                </div>
                {/* New eCPM Card */}
                <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
                    <div className="text-gray-500 text-xs mb-1">eCPM</div>
                    <div className="text-xl font-bold text-gray-900">${client.conversionMetrics?.ecpm.toFixed(2) || '0.00'}</div>
                    <div className="text-gray-400 text-xs mt-1">竞价能力指标</div>
                </div>
                <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
                    <div className="text-gray-500 text-xs mb-1">付费率 (PUR)</div>
                    <div className="text-xl font-bold text-gray-900">{client.conversionMetrics?.payRate || 0}%</div>
                </div>
                <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
                    <div className="text-gray-500 text-xs mb-1">LTV</div>
                    <div className="text-xl font-bold text-gray-900">${client.conversionMetrics?.ltv || 0}</div>
                </div>
            </div>

            {/* App Metrics Trend (Impressions, Downloads, Activations) */}
            <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
                <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-6">
                    <Activity size={18} className="text-indigo-600"/> 应用数据趋势 (曝光/下载/激活)
                </h3>
                {client.funnelHistory && client.funnelHistory.length > 0 ? (
                    <>
                        <div className="h-64 mb-6">
                            <MultiLineChart 
                                data={client.funnelHistory} 
                                lines={[
                                    { key: 'impressions', color: '#94a3b8', name: '曝光量' },
                                    { key: 'downloads', color: '#6366f1', name: '下载量' },
                                    { key: 'activations', color: '#10b981', name: '激活量' },
                                ]}
                            />
                        </div>
                        <div className="overflow-x-auto">
                            <table className="w-full text-sm text-left border-collapse">
                                <thead className="bg-gray-50 text-gray-500">
                                    <tr>
                                        <th className="px-4 py-2 font-medium">日期</th>
                                        <th className="px-4 py-2 font-medium">曝光量</th>
                                        <th className="px-4 py-2 font-medium">下载量</th>
                                        <th className="px-4 py-2 font-medium">下载率</th>
                                        <th className="px-4 py-2 font-medium">激活量</th>
                                        <th className="px-4 py-2 font-medium">激活率</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-100">
                                    {[...client.funnelHistory].reverse().map((row, idx) => (
                                        <tr key={idx} className="hover:bg-gray-50">
                                            <td className="px-4 py-2">{row.date}</td>
                                            <td className="px-4 py-2">{row.impressions.toLocaleString()}</td>
                                            <td className="px-4 py-2">{row.downloads.toLocaleString()}</td>
                                            <td className="px-4 py-2 text-gray-500">{((row.downloads / row.impressions) * 100).toFixed(2)}%</td>
                                            <td className="px-4 py-2 font-semibold text-gray-800">{row.activations.toLocaleString()}</td>
                                            <td className="px-4 py-2 text-gray-500">{((row.activations / row.downloads) * 100).toFixed(1)}%</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </>
                ) : (
                    <div className="py-8 text-center text-gray-400">暂无历史趋势数据</div>
                )}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Conversion & Funnel */}
                <div className="lg:col-span-2 bg-white rounded-xl p-6 shadow-sm border border-gray-100">
                    <div className="flex justify-between items-center mb-4">
                        <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2"><Target size={18} className="text-indigo-600"/> 后端转化漏斗</h3>
                    </div>
                    <div className="grid grid-cols-3 gap-4 mb-6 text-center">
                        <div className="bg-gray-50 p-3 rounded-lg">
                            <div className="text-xs text-gray-500">次日留存</div>
                            <div className="text-lg font-semibold text-gray-800">{client.conversionMetrics?.retention1d || 0}%</div>
                        </div>
                        <div className="bg-gray-50 p-3 rounded-lg">
                            <div className="text-xs text-gray-500">7日留存</div>
                            <div className="text-lg font-semibold text-gray-800">{client.conversionMetrics?.retention7d || 0}%</div>
                        </div>
                        <div className="bg-gray-50 p-3 rounded-lg">
                            <div className="text-xs text-gray-500">ROAS (IAP/IAA)</div>
                            <div className="text-lg font-semibold text-gray-800">{client.conversionMetrics?.roasIAP || 0} / {client.conversionMetrics?.roasIAA || 0}</div>
                        </div>
                    </div>
                    {client.conversionMetrics?.funnel && (
                        <FunnelChart data={client.conversionMetrics.funnel} />
                    )}
                </div>

                {/* Channel Monitoring */}
                <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
                    <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-4">
                        <Share2 size={18} className="text-indigo-600"/> 渠道监控
                    </h3>
                    <div className="h-64">
                        {client.channelDistribution ? (
                            <DonutChart data={client.channelDistribution} />
                        ) : (
                            <div className="flex items-center justify-center h-full text-gray-400 text-sm">暂无渠道数据</div>
                        )}
                    </div>
                    <div className="mt-4 p-3 bg-indigo-50 rounded-lg text-xs text-indigo-800">
                        <strong>分发洞察:</strong> 本平台分发量目前占比最高，建议继续保持优化，同时关注其他三方商店的增长趋势。
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Bidding & Competition */}
                <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
                    <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-4">
                        <DollarSign size={18} className="text-indigo-600"/> 竞价与诊断
                    </h3>
                    <div className="mb-6">
                        <div className="flex justify-between items-center mb-2">
                             <span className="text-sm text-gray-600">平均竞胜率 (Win Rate)</span>
                             <span className="font-bold text-gray-900">{client.biddingData?.winRate || 0}%</span>
                        </div>
                        <div className="w-full bg-gray-100 rounded-full h-2">
                            <div className="bg-indigo-500 h-2 rounded-full" style={{width: `${client.biddingData?.winRate || 0}%`}}></div>
                        </div>
                    </div>
                    <div className="mb-4">
                        <div className="text-xs text-gray-500 mb-2 font-medium uppercase">竞价失败原因分析</div>
                        <div className="space-y-3">
                            {client.biddingData?.lossReasons.map(r => (
                                <div key={r.reason}>
                                    <div className="flex justify-between text-xs mb-1">
                                        <span>{r.reason}</span>
                                        <span className="text-gray-500">{r.percentage}%</span>
                                    </div>
                                    <div className="w-full bg-gray-50 rounded-full h-1.5">
                                        <div className="bg-orange-400 h-1.5 rounded-full" style={{width: `${r.percentage}%`}}></div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Creative DNA */}
                <div className="lg:col-span-2 bg-white rounded-xl p-6 shadow-sm border border-gray-100">
                    <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-4">
                        <Sparkles size={18} className="text-indigo-600"/> 创意 DNA 与素材分析
                    </h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                             <h4 className="text-sm font-medium text-gray-700 mb-3">Top 表现素材</h4>
                             <div className="space-y-3">
                                {client.creativeStats?.topCreatives.map(c => (
                                    <div key={c.id} className="flex gap-3 p-2 bg-gray-50 rounded-lg hover:bg-gray-100 transition-colors">
                                        <img src={c.url} className="w-16 h-10 object-cover rounded bg-gray-200" alt={c.name} />
                                        <div className="flex-1 min-w-0">
                                            <div className="text-sm font-medium text-gray-900 truncate">{c.name}</div>
                                            <div className="flex items-center gap-2 text-xs text-gray-500">
                                                <span className="px-1.5 py-0.5 bg-white border rounded uppercase text-[10px]">{c.type}</span>
                                                <span className="text-green-600 font-medium">CTR: {c.ctr}%</span>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                             </div>
                        </div>
                        <div>
                            <div className="mb-4">
                                <h4 className="text-sm font-medium text-gray-700 mb-2">用户偏好标签</h4>
                                <div className="flex flex-wrap gap-2">
                                    {client.creativeStats?.tags.map(tag => (
                                        <span key={tag} className="px-3 py-1 bg-indigo-50 text-indigo-700 rounded-full text-xs font-medium">
                                            #{tag}
                                        </span>
                                    ))}
                                </div>
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div className="bg-gray-50 p-3 rounded-lg text-center">
                                    <div className="text-xs text-gray-500">素材衰退周期</div>
                                    <div className="text-lg font-bold text-gray-900">{client.creativeStats?.lifecycleDays} 天</div>
                                </div>
                                <div className="bg-gray-50 p-3 rounded-lg text-center">
                                    <div className="text-xs text-gray-500">拒审率</div>
                                    <div className="text-lg font-bold text-gray-900">{client.creativeStats?.rejectionRate}%</div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

             {/* Growth & Opportunities */}
             <div className="bg-gradient-to-br from-indigo-50 to-blue-50 rounded-xl p-6 shadow-sm border border-indigo-100">
                <div className="flex justify-between items-start mb-4">
                    <h3 className="text-lg font-semibold text-indigo-900 flex items-center gap-2">
                        <Zap size={18} className="text-indigo-600"/> 增长机会探测
                    </h3>
                    <span className="bg-white text-indigo-600 text-xs px-2 py-1 rounded border border-indigo-100 font-medium">AI Generated</span>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div>
                        <div className="text-xs font-semibold text-indigo-400 uppercase tracking-wider mb-2">推荐搜索关键词</div>
                        <ul className="space-y-2">
                            {client.growthOpp?.recommendedKeywords.map((kw, i) => (
                                <li key={i} className="flex justify-between items-center bg-white/60 p-2 rounded text-sm text-indigo-900">
                                    <span>{kw.keyword}</span>
                                    <span className={`text-xs px-1.5 py-0.5 rounded ${
                                        kw.competition === 'Low' ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'
                                    }`}>{kw.competition} Comp</span>
                                </li>
                            ))}
                        </ul>
                    </div>
                    <div>
                        <div className="text-xs font-semibold text-indigo-400 uppercase tracking-wider mb-2">缺失流量版位</div>
                        <ul className="space-y-2">
                            {client.growthOpp?.missedPlacements.map((mp, i) => (
                                <li key={i} className="flex justify-between items-center bg-white/60 p-2 rounded text-sm text-indigo-900">
                                    <span>{mp.name}</span>
                                    <span className="text-green-600 font-semibold text-xs">{mp.potentialLift}</span>
                                </li>
                            ))}
                        </ul>
                    </div>
                    <div>
                        <div className="text-xs font-semibold text-indigo-400 uppercase tracking-wider mb-2">行业流行趋势</div>
                        <div className="flex flex-wrap gap-2">
                             {client.growthOpp?.industryTrends.map((trend, i) => (
                                <span key={i} className="bg-white px-3 py-1 rounded-full text-xs text-indigo-800 border border-indigo-100 shadow-sm">
                                    {trend}
                                </span>
                             ))}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
  };

  const renderChurnTab = () => (
    <div className="space-y-6">
        <div className="bg-red-50 rounded-xl p-6 border border-red-100">
             <div className="flex items-start gap-4">
                <div className="p-3 bg-red-100 rounded-full text-red-600">
                    <ShieldAlert size={24} />
                </div>
                <div>
                    <h3 className="text-lg font-bold text-red-900 mb-1">流失风险预警</h3>
                    <p className="text-red-700 mb-4">该客户已被系统标记为高风险流失客户 (Risk Score: {client.riskScore})。主要原因为：{client.churnReason}</p>

                    <div className="bg-white p-4 rounded-lg border border-red-100">
                        <h4 className="text-sm font-semibold text-gray-800 mb-2">推荐挽留方案 (AI Recommended)</h4>
                        <ul className="space-y-2">
                            {client.retentionPlan?.map((plan, i) => (
                                <li key={i} className="flex items-start gap-2 text-sm text-gray-700">
                                    <CheckCircle2 size={16} className="text-green-500 mt-0.5 flex-shrink-0" />
                                    <span>{plan}</span>
                                </li>
                            ))}
                        </ul>
                    </div>
                </div>
             </div>
        </div>

        <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
            <h3 className="text-lg font-semibold text-gray-800 mb-4">历史活跃度回溯</h3>
            <div className="h-64">
                <TrendChart data={client.spendTrend || []} dataKey="spend" color="#ef4444" />
            </div>
        </div>
    </div>
  );

  return (
    <div className="max-w-7xl mx-auto pb-12">
      {renderHeader()}

      <div className="flex gap-4 mb-6 border-b border-gray-200">
        <button 
          onClick={() => setActiveTab('performance')}
          className={`pb-3 px-1 text-sm font-medium transition-colors border-b-2 ${activeTab === 'performance' ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
        >
          全景绩效
        </button>
        <button 
          onClick={() => setActiveTab('prospect')}
          className={`pb-3 px-1 text-sm font-medium transition-colors border-b-2 ${activeTab === 'prospect' ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
        >
          拓展与竞品
        </button>
        <button 
          onClick={() => setActiveTab('churn')}
          className={`pb-3 px-1 text-sm font-medium transition-colors border-b-2 ${activeTab === 'churn' ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
        >
          风险与健康度
        </button>
      </div>

      {activeTab === 'performance' && renderPerformanceTab()}
      {activeTab === 'prospect' && renderProspectTab()}
      {activeTab === 'churn' && renderChurnTab()}

      {/* AI Assistant Floating Action */}
      <div className="fixed bottom-8 right-8 z-30">
        <button 
          onClick={handleGenerateInsight}
          disabled={loadingInsight}
          className="flex items-center gap-2 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white px-6 py-4 rounded-full shadow-lg transition-all transform hover:scale-105 disabled:opacity-70 disabled:cursor-not-allowed"
        >
          {loadingInsight ? (
            <>
                <div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent"></div>
                <span>正在分析全域数据...</span>
            </>
          ) : (
            <>
                <BrainCircuit size={20} />
                <span>生成 AI 深度洞察</span>
            </>
          )}
        </button>
      </div>

      {/* AI Insight Modal/Drawer */}
      {insight && (
        <div className="fixed inset-0 z-40 overflow-y-auto" aria-labelledby="modal-title" role="dialog" aria-modal="true">
            <div className="flex items-end justify-center min-h-screen pt-4 px-4 pb-20 text-center sm:block sm:p-0">
                <div className="fixed inset-0 bg-gray-500 bg-opacity-75 transition-opacity" aria-hidden="true" onClick={() => setInsight(null)}></div>
                <span className="hidden sm:inline-block sm:align-middle sm:h-screen" aria-hidden="true">&#8203;</span>
                <div className="inline-block align-bottom bg-white rounded-lg text-left overflow-hidden shadow-xl transform transition-all sm:my-8 sm:align-middle sm:max-w-2xl sm:w-full">
                    <div className="bg-white px-4 pt-5 pb-4 sm:p-6 sm:pb-4">
                        <div className="sm:flex sm:items-start">
                            <div className="mx-auto flex-shrink-0 flex items-center justify-center h-12 w-12 rounded-full bg-blue-100 sm:mx-0 sm:h-10 sm:w-10">
                                <Sparkles className="h-6 w-6 text-blue-600" />
                            </div>
                            <div className="mt-3 text-center sm:mt-0 sm:ml-4 sm:text-left w-full">
                                <h3 className="text-lg leading-6 font-medium text-gray-900" id="modal-title">AI 智能诊断报告</h3>
                                <div className="mt-4 space-y-4">
                                    <div className="bg-gray-50 p-4 rounded-lg">
                                        <h4 className="text-sm font-bold text-gray-700 mb-2">高管摘要</h4>
                                        <p className="text-sm text-gray-600 leading-relaxed">{insight.summary}</p>
                                    </div>

                                    <div>
                                        <h4 className="text-sm font-bold text-gray-700 mb-2">关键行动建议 (Action Items)</h4>
                                        <ul className="space-y-2">
                                            {insight.actionItems.map((item, idx) => (
                                                <li key={idx} className="flex items-start gap-2 text-sm text-gray-600 bg-blue-50/50 p-2 rounded">
                                                    <span className="bg-blue-100 text-blue-700 w-5 h-5 rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0">{idx + 1}</span>
                                                    {item}
                                                </li>
                                            ))}
                                        </ul>
                                    </div>

                                    {insight.prediction && (
                                        <div className="border-t border-gray-100 pt-3">
                                            <h4 className="text-sm font-bold text-gray-700 mb-1">战略预测</h4>
                                            <p className="text-sm text-gray-500 italic">"{insight.prediction}"</p>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                    <div className="bg-gray-50 px-4 py-3 sm:px-6 sm:flex sm:flex-row-reverse">
                        <button 
                            type="button" 
                            className="w-full inline-flex justify-center rounded-md border border-transparent shadow-sm px-4 py-2 bg-blue-600 text-base font-medium text-white hover:bg-blue-700 focus:outline-none sm:ml-3 sm:w-auto sm:text-sm"
                            onClick={() => setInsight(null)}
                        >
                            确认并关闭
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};
